import React, { useRef, useState } from 'react';
import { PageContainer } from '@ant-design/pro-layout';
import type { ProColumns, ActionType } from '@ant-design/pro-table';
import ProTable from '@ant-design/pro-table';
import { consoleAudits } from '@/services/api';
import type { API } from '@/services/typings';
import { SaveCsv, csvFormat, getTablePaginationConfig, t } from '../../../global';
import { useIntl } from '@umijs/max';
import { Breadcrumb, Button, Tooltip } from 'antd';
import { ContactsOutlined, ControlOutlined, FundProjectionScreenOutlined, QuestionCircleFilled, UserOutlined, UsergroupAddOutlined, UsergroupDeleteOutlined } from '@ant-design/icons';

const AuditList: React.FC = () => {
  const actionRef = useRef<ActionType>();
  const [pageParams, setPageParams] = useState<Partial<API.PageParams>>();
  const intl = useIntl();

  const plain = (text: string, defaultMessage = '') => t(`pages.AuditList.ConsoleAuditList.${text}`, true, defaultMessage || text, intl) as string;

  const typeEnumMap = (i: number) => {
    switch (i) {
      case 0:
        return plain('Group Management');
      case 1:
        return plain('User Management');
      case 2:
        return plain('Device Management');
      case 3:
        return plain('Address Book Management');
      case 4:
        return plain('Admin Roles Management');
      case 5:
        return plain('Control Roles Management');
      default:
        return i.toString();
    }
  };

  const opeartionEnumMap = (i: number) => {
    switch (i) {
      case 0:
        return plain('User Login');
      case 1:
        return plain('Add Group');
      case 2:
        return plain('Add User');
      case 3:
        return plain('Add Device');
      case 4:
        return plain('Delete Groups');
      case 5:
        return plain('Disconnect Device');
      case 6:
        return plain('Enable Users');
      case 7:
        return plain('Disable Users');
      case 8:
        return plain('Enable Devices');
      case 9:
        return plain('Disable Devices');
      case 10:
        return plain('Update Group');
      case 11:
        return plain('Update User');
      case 12:
        return plain('Update Device');
      case 13:
        return plain('Delete User');
      case 14:
        return plain('Delete Device');
      case 15:
        return plain('Add Address Book');
      case 16:
        return plain('Delete Address Book');
      case 17:
        return plain('Change Address Book Name');
      case 18:
        return plain('Delete Devices in the Address Book Recycle Bin');
      case 19:
        return plain('Empty Address Book Recycle Bin');
      case 20:
        return plain('Add Address Book Permission');
      case 21:
        return plain('Delete Address Book Permission');
      case 22:
        return plain('Update Address Book Permission');
      case 23:
        return t('reset_2fa', true) as string;
      case 24:
        return t('disable_email_login_verification', true) as string;
      case 25:
        return t('enable_2fa_enforcement', true) as string;
      case 26:
        return t('disable_2fa_enforcement', true) as string;
      case 27:
        return t('force_logout', true) as string;
      case 28:
        return t('reset_password', true) as string;
      case 29:
        return t('create_admin_role', true) as string;
      case 30:
        return t('delete_admin_role', true) as string;
      case 31:
        return t('update_admin_role', true) as string;
      case 32:
        return t('add_users_to_admin_role', true) as string;
      case 33:
        return t('remove_users_from_admin_role', true) as string;
      case 34:
        return t('create_control_role', true) as string;
      case 35:
        return t('update_control_role', true) as string;
      case 36:
        return t('delete_control_role', true) as string;
      case 37:
        return t('assign_users_to_control_role', true) as string;
      case 38:
        return t('remove_users_from_control_role', true) as string;
      // don't forget to change opeartionEnum
      default:
        return i.toString();
    }
  };

  const typeEnum = {
    0: {
      text: typeEnumMap(0),
    },
    1: {
      text: typeEnumMap(1),
    },
    2: {
      text: typeEnumMap(2),
    },
    3: {
      text: typeEnumMap(3),
    },
    4: {
      text: typeEnumMap(4),
    },
    5: {
      text: typeEnumMap(5),
    },
  };

  // skip 0
  const opeartionEnum = Object.fromEntries(Array.from({ length: 38 }, (_, i) => [i + 1, { text: opeartionEnumMap(i + 1) }]));

  const renderDetail = (record: API.ConsoleAuditListItem) => {
    let txt = '';
    try {
      const o = JSON.parse(record.info || '');
      let cnt = 0;
      for (const k in o) {
        if (cnt > 0) {
          txt += '; ';
        }
        txt += `${plain(k)}: ${o[k]}`;
        cnt++;
      }
    } catch (e) { }
    return txt;
  };

  const exportCsv = async () => {
    let allItems: API.ConsoleAuditListItem[] = [];
    let total = 0;
    const pageSize = 100;
    let current = 0;
    do {
      current++;
      const items = await consoleAudits({ ...pageParams, current: current, pageSize: pageSize });
      if (total == 0 && items.total != null) {
        total = items.total;
      }
      if (items.data != null) {
        allItems = allItems.concat(items.data);
      }
    } while (current < 10 && pageSize * current < total);

    const titles = [
      plain('Type'),
      plain('User'),
      plain('Operation'),
      plain('Time'),
      plain('Detail'),
    ];
    const rows: string[][] = [];
    allItems.forEach((record) => {
      const row: string[] = [];
      row.push(typeEnumMap(record.typ || 0));
      row.push(record.operator || '');
      row.push(opeartionEnumMap(record.iop || 0));
      row.push(csvFormat(new Date((record.created_at || 0) * 1000).toLocaleString()));
      row.push(renderDetail(record));
      rows.push(row);
    });
    SaveCsv(titles, rows, plain('exportFilename', 'ConsoleAudit'));
  };

  const columns: ProColumns<API.ConsoleAuditListItem>[] = [
    {
      title: t('Type'),
      dataIndex: 'typ',
      valueType: 'select',
      valueEnum: typeEnum,
      width: 60,
      render: (_, record) => {
        let icon;
        switch (record.typ || 0) {
          case 0:
            icon = <UsergroupDeleteOutlined />;
            break;
          case 1:
            icon = <UserOutlined />;
            break;
          case 2:
            icon = <FundProjectionScreenOutlined />;
            break;
          case 3:
            icon = <ContactsOutlined />;
            break;
          case 4:
            icon = <UsergroupAddOutlined />;
            break;
          case 5:
            icon = <ControlOutlined />;
            break;
          default:
            icon = <QuestionCircleFilled />;
            break;
        };
        return <Tooltip title={typeEnumMap(record.typ || 0)}>{icon}</Tooltip>;
      },
    },
    {
      title: t('User'),
      dataIndex: 'operator',
    },
    {
      title: t('pages.AuditList.ConsoleAuditList.Operation', true, 'Operation'),
      dataIndex: 'iop',
      valueType: 'select',
      valueEnum: opeartionEnum,
    },
    {
      title: t('Time'),
      dataIndex: 'created_at',
      valueType: 'dateTime',
      render: (_, record) => new Date((record.created_at || 0) * 1000).toLocaleString(),
    },
    {
      title: t('Detail'),
      search: false,
      width: 200,
      render: (_, record) => {
        return renderDetail(record);
      },
    },
  ];

  return (
    <PageContainer
      breadcrumbRender={() => (
        <Breadcrumb items={[
          { title: t('menu.list.audit-list', true) },
          { title: t('menu.list.audit-list.Console', true) },
        ]} />
      )}
    >
      <ProTable<API.ConsoleAuditListItem, API.PageParams>
        headerTitle={t('Log List')}
        columnsState={{ persistenceType: 'localStorage', persistenceKey: 'consolelist_columns_state' }}
        actionRef={actionRef}
        rowKey="guid"
        search={{
          labelWidth: 120,
        }}
        request={consoleAudits}
        columns={columns}
        beforeSearchSubmit={(params) => {
          setPageParams(params);
          return params;
        }}
        toolBarRender={() => [
          <Tooltip title={t('exportCsvTip', true, 'Export up to 1000 records at a time')}>
            <Button type="default" onClick={exportCsv}>
              {t('Export as csv')}
            </Button>
          </Tooltip>,
        ]}
        pagination={getTablePaginationConfig("console_audit_list")}
      />
    </PageContainer>
  );
};

export default AuditList;
